+# Version comparison helper: returns 0 if $1 > $2
+version_gt() {
+    if command -v sort &> /dev/null; then
+        [[ "$(printf '%s\n' "$1" "$2" | sort -V | tail -n1)" == "$1" && "$1" != "$2" ]]
+    else
+        [[ "$1" > "$2" ]]
+    fi
+}
